import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { DashboardStats } from '../../core/models';

/**
 * MiniERP dashboard — cross-role summary. Reads a single DashboardStats object
 * (open POs, open SOs, unpaid invoices, stock value in cents). The service_agent
 * stage wires this to ApiService.getDashboard() in ngOnInit.
 */
@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './dashboard.component.html',
  styleUrl: './dashboard.component.css',
})
export class DashboardComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  readonly stats = signal<DashboardStats>({
    openPurchaseOrders: 3,
    openSalesOrders: 4,
    unpaidInvoices: 2,
    stockValueCents: 4_215_00,
  });

  ngOnInit(): void {
    // service_agent: load this.stats() from ApiService.getDashboard().
  }

  money(cents: number): string {
    return (cents / 100).toLocaleString(undefined, { style: 'currency', currency: 'USD' });
  }
}
